1	const PROCESSING_FEE = 5;
2	const COMPONENT_BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_UNIT_PREMIUM = 25;
5	
6	const CURSE_SURCHARGE_RATE = 0.5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	
9	const BASE_PREMIUMS: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: COMPONENT_UNIT_PREMIUM,
15	  moonstone: COMPONENT_UNIT_PREMIUM,
16	};
17	
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	
20	interface Item {
21	  type: string;
22	  material?: string;
23	  enchantment?: number;
24	  cursed?: boolean;
25	}
26	
27	interface QuoteStep {
28	  op: "quote";
29	  items: Item[];
30	}
31	
32	interface Scenario {
33	  customer: { yearsWithMHPCO: number };
34	  steps: QuoteStep[];
35	}
36	
37	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
38	
39	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
40	
41	const countsByType = (items: Item[]): Map<string, number> =>
42	  items.reduce((counts, item) => {
43	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
44	    return counts;
45	  }, new Map<string, number>());
46	
47	const componentGroupPremium = (count: number): number =>
48	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_UNIT_PREMIUM;
49	
50	const sumComponentPremiums = (components: Item[]): number =>
51	  Array.from(countsByType(components).values()).reduce(
52	    (total, count) => total + componentGroupPremium(count),
53	    0,
54	  );
55	
56	const sumMainItemPremiums = (mainItems: Item[]): number =>
57	  mainItems.reduce((total, item) => total + basePremiumFor(item), 0);
58	
59	const policyBasePremium = (items: Item[]): number => {
60	  const components = items.filter(isComponent);
61	  const mainItems = items.filter((item) => !isComponent(item));
62	  return sumMainItemPremiums(mainItems) + sumComponentPremiums(components);
63	};
64	
65	const itemModifierSurcharge = (item: Item): number => {
66	  if (isComponent(item)) return 0;
67	  return item.cursed ? basePremiumFor(item) * CURSE_SURCHARGE_RATE : 0;
68	};
69	
70	const sumItemModifiers = (items: Item[]): number =>
71	  items.reduce((total, item) => total + itemModifierSurcharge(item), 0);
72	
73	const policyModifierAmount = (policyBase: number): number => policyBase * FIRST_INSURANCE_RATE;
74	
75	const quoteStep = (step: QuoteStep) => {
76	  const policyBase = policyBasePremium(step.items);
77	  const itemSurcharges = sumItemModifiers(step.items);
78	  const policyMods = policyModifierAmount(policyBase);
79	  const premium = policyBase + itemSurcharges + policyMods + PROCESSING_FEE;
80	  return { premium: Math.ceil(premium) };
81	};
82	
83	export const runScenario = (input: unknown): unknown => {
84	  const scenario = input as Scenario;
85	  return { results: scenario.steps.map(quoteStep) };
86	};
